1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	};
9	
10	interface Item {
11	  type: string;
12	}
13	
14	interface QuoteStep {
15	  op: "quote";
16	  items: Item[];
17	}
18	
19	interface Scenario {
20	  customer: { yearsWithMHPCO: number };
21	  steps: QuoteStep[];
22	}
23	
24	export function runScenario(input: unknown): unknown {
25	  const scenario = input as Scenario;
26	  const results = scenario.steps.map((step) => {
27	    const basePremium = step.items.reduce(
28	      (sum, item) => sum + (BASE_PREMIUM[item.type] ?? 0),
29	      0,
30	    );
31	    const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
32	    const premium = basePremium + firstInsurance + PROCESSING_FEE;
33	    return { premium };
34	  });
35	  return { results };
36	}
